 */
class MultiLineIfElseRuleEmptyBlockTest {
    private val multiLineIfElseRuleAssertThat = assertThatRule { MultiLineIfElseRule() }

    @Test
    fun `Given invalid code with empty then block followed by else if with empty then - no crash`() {
        val code =
            """
            if ("a" == "b") {
            } else if ("b" == "c") else {
            }
            """.trimIndent()
        // The code should not crash with NullPointerException
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given valid code with same structure but non-empty blocks`() {
        val code =
            """
            if ("a" == "b") {
                return 1
            } else if ("b" == "c") {
                return 2
            } else {
                return 3
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }
}"}

